class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        must_edges = []
        non_must_edges = []

        for u, v, s, must in edges:
            if must:
                must_edges.append((u, v, s))
            else:
                non_must_edges.append((s, u, v))

        non_must_edges.sort()

        parent = list(range(n))
        rank = [0] * n

        def find(x):
            if x != parent[x]:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x, root_y = find(x), find(y)
            if root_x != root_y:
                if rank[root_x] > rank[root_y]:
                    parent[root_y] = root_x
                elif rank[root_x] < rank[root_y]:
                    parent[root_x] = root_y
                else:
                    parent[root_y] = root_x
                    rank[root_x] += 1

        for u, v, s in must_edges:
            if find(u) != find(v):
                union(u, v)
            else:
                return -1

        count = sum(1 for u, v, s in must_edges if find(u) != find(v))
        if count == n - 1:
            min_strength = min(s for u, v, s in must_edges)
        else:
            min_strength = float('inf')

        for s, u, v in non_must_edges:
            if find(u) != find(v):
                union(u, v)
                count += 1
                if count == n - 1:
                    if k > 0:
                        min_strength = max(min_strength, s * 2)
                        k -= 1
                    else:
                        min_strength = max(min_strength, s)

        return min_strength if count == n - 1 else -1
```
